import { DataTree, TID } from "@svar-ui/lib-state";
import { ITask, IParsedTask, TSort, TFilterHandler, IGanttColumn } from "./types";
export default class GanttDataTree extends DataTree<IParsedTask> {
    private _filteredIds;
    constructor(tasks?: Partial<ITask>[]);
    parse(tasks: Partial<ITask>[], parent: TID): void;
    getBranch(id: TID): IParsedTask[];
    contains(id: TID, target: TID): boolean;
    getIndexById(id: TID): number;
    add(task: Partial<ITask>, index: number): IParsedTask;
    copy(taskObj: ITask, parent: TID, ind: number): TID[][];
    remove(id: TID): void;
    normalizeTask(task: Partial<ITask>): ITask;
    getSummaryId(id: TID): TID | null;
    getSummaryId(id: TID, all: boolean): TID[] | null;
    sort(conf: TSort[], columns: IGanttColumn[]): void;
    sortBranch(conf: TSort[], parent: TID, columns: IGanttColumn[]): void;
    serialize(): Partial<ITask>[];
    clear(): void;
    filterTree(filter?: TFilterHandler, open?: boolean): void;
    toArray(all?: boolean): IParsedTask[];
    isFilteredId(id: TID): boolean;
    hasChildItems(task: Partial<IParsedTask>): boolean;
}
